sp_widget.client_script:
api.controller = function($scope, $element, $rootScope, $timeout, snAttachmentHandler, $http, spUtil, userPreferences, $filter, i18n, spAriaUtil) {
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; lines from new controller example
/* widget controller */
	var c = this;

    // Many of these fields are more configuration-type fields than profile fields. We still want to display
    // these to a user who is configuring their 'settings', but we shouldn't show them on a user profile page.
    // We need to handle this better.
    var fieldExcludes = {
        sys_user: ['name', 'introduction', 'title', 'department', 'location', 'photo',
            'manager', 'company'
        ],
        live_profile: ['short_description', 'photo']
    };

    $scope.$watch('data.dateTimeFormat', function() {
        if ($scope.data.dateTimeFormat != g_user_date_time_format)
            $scope.data.dateTimeFormatChanged = true;
    });

    $scope.uploadNewProfilePicture = function($event) {
        $event.stopPropagation();
        if ($event.keyCode === 9) {
            return;
        }
        var $el = $element.find('input[type=file]');
        $el.click();
    };

    $scope.attachFiles = function(files) {
        var file = files.files[0];

        var validImage = false;

        switch (file.type) {
            case 'image/jpeg':
            case 'image/png':
            case 'image/bmp':
            case 'image/x-windows-bmp':
            case 'image/gif':
            case 'image/x-icon':
            case 'image/svg+xml':
                validImage = true;
                break;
            default:
                break;
        }

        if (!validImage) {
            alert(file.name + " " + i18n.getMessage("isn't a recognized image file format"));
            return;
        }

        snAttachmentHandler.create("live_profile", $scope.data.liveProfileID).uploadAttachment(file, {
            sysparm_fieldname: "photo"
        }).then(function(response) {
            var obj = {};
            obj.newAvatarId = response.sys_id;
            $scope.avatarPicture = {
                'background-image': "url('" + response.sys_id + ".iix')",
                'color': 'transparent'
            };
            $rootScope.$broadcast("sp.avatar_changed", obj);
            // timeout is required for screen reader to pick up the message once file upload prompt is dismissed
            $timeout(function() {
                spAriaUtil.sendLiveMessage(i18n.getMessage('Profile picture updated successfully'));
            }, 500);
        });
    };

    $scope.avatarPicture = "";

    $http.get('/api/now/live/profiles/sys_user.' + $scope.data.sysUserID).then(function(response) {
        if (response.data.result && response.data.result.avatar) {
            var avatarPicture = response.data.result.avatar.replace("?t=small", "");
            $scope.avatarPicture = {
                'background-image': "url('" + avatarPicture + "')",
                'color': 'transparent'
            };
        }
    });

    spUtil.recordWatch($scope, "sys_user", "sys_id=" + $scope.data.sysUserID);
  	spUtil.recordWatch($scope, "live_profile", "sys_id=" + $scope.data.liveProfileID);

    $scope.getSysUserModelFields = function() {
        if ($scope.data.userExists) {
            return $scope.data.sysUserModelList
                .filter(function(field) {
                    return $scope.displayField("sys_user", field.name);
                });
        }
        return [];
    };

    $scope.data.dateTimeFormatChanged = false;

    // get the list of values for a property using the concourse picker api (timezone, language)
    var getListValuesForProperty = function(endpoint, listProperty) {
        $http.get('/api/now/ui/concoursepicker/' + endpoint).then(function(response) {
            if (response && response.data && response.data.result && response.data.result.list) {
                if (!listProperty.list)
                    listProperty.list = [];

                listProperty.list = response.data.result.list;
                if (response.data.result.current) {
                    if (!listProperty.current)
                        listProperty.current = {};
                    listProperty.current = $filter('filter')(listProperty.list, {
                        value: response.data.result.current
                    }, true)[0];
                }
            }
        });
    };

    // list of user properties that are not user preferences
    $scope.data.listProperties = {
        timezone: {},
        encryption: {},
        language: {}
    };

    // initialize dropbox data
    getListValuesForProperty('timezone', $scope.data.listProperties.timezone);
    getListValuesForProperty('language', $scope.data.listProperties.language);
    getListValuesForProperty('encryption', $scope.data.listProperties.encryption);

    var models = {
        sys_user: $scope.data.sysUserModel,
        live_profile: $scope.data.liveProfileModel
    };

    $scope.displayField = function(tableName, field, isHeader) {
        if (!isHeader && fieldExcludes[tableName].indexOf(field) > -1) return false;

        if (models[tableName][field] && models[tableName][field].type === "boolean") return false;

        if ($scope.data.isLoggedInUsersProfile) {
            if (models[tableName][field] && models[tableName][field].readonly)
                return models[tableName][field].displayValue;
            else
                return models[tableName][field];
        } else {
            return models[tableName][field] && models[tableName][field].displayValue;
        }
    };

    $timeout(function() {
        $rootScope.$broadcast('finishedChanged', {
            profile: $scope.data.teamData
        });
    });

    $scope.sysUserModelFields = $scope.getSysUserModelFields();


	// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal; comment out onCancel()
	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
	//Added cancel and submit buttons to cloned widget
// 	c.onCancel = function() {
//         $scope.$parent.$parent.$dismiss();
//     };

	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
	// Submit is not currently active in the HTML so comment out here
//     c.onSubmit = function() {
//         c.data.submit = true;
//         $scope.server.update().then(function() {
//             $scope.$parent.$parent.$dismiss();
//         });

//     };
};

sp_widget.css:
/* RAJ - added for the card to be different than other places*/
.profile-card-container {
  display: flex;
  flex-direction: row;
  /* DFCT0011552 align-items: start; */
  align-items: center;
  justify-content: start;
  /* DFCT0011552 */
  flex-grow: 1;
}

.profile-card-text-column{
  display: flex;
  flex-direction: column;
  align-items: start;
  justify-content: start;
  margin-left:20px;
}

.avatar-container-card {
  -webkit-box-flex: 0 0 auto;
  -moz-box-flex: 0 0 auto;
  -webkit-flex: 0 0 auto;
  -ms-flex: 0 0 auto;
  flex: 0 0 auto;
  background-size: cover;
  border-radius: 50%;
  height: 6.4rem;
  width: 6.4rem;
  /* DFCT0011552 cursor: pointer; */
  color: #ffffff;
  display: inline-block;
  font-weight: bold;
  position: relative;
  text-align: center;
  vertical-align: middle;
}

.avatar-container-card .avatar .sub-avatar {
  -moz-user-select: -moz-none;
  -ms-user-select: none;
  -webkit-user-select: none;
  user-select: none;
  width: 50%;
  height: 50%;
  display: block;
  overflow: hidden;
  border-radius: 50%;
  background: rgba(0, 0, 0, 0.15) center;
  background-size: cover;
  box-sizing: border-box;
  font-size: 0.8rem;
  line-height: 1.6rem;
}
.avatar-container-card .avatar.soloAvatar .sub-avatar {
  width: 100%;
  height: 100%;
  border-radius: 0;
  font-size: 1rem;
  line-height: 3.2rem;
}

.avatar-container-card .avatar.soloAvatar {
  background: rgba(0, 0, 0, 0.15) center;
  border-radius: 50%;
}
.avatar-container-card .avatar {
  justify-content: center;
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.profile-card-name-text {
  font-family:SourceSansPro;
  font-size:14px;
  font-weight:600;
  color:#000000;
}
.profile-card-text {
  font-family:SourceSansPro;
  font-size:14px;
  font-weight:400;
  display:inline;
  color:#757575;
}


.list-group-item {
  border: none;
  padding: 5px 15px;

  .btn-link {
  	padding-left: 0;
    padding-right: 0;
  }
}

.user-name {
  word-break: break-word;
}

.select2-container.select2-allowclear .select2-choice .select2-chosen {
  margin-right: 60px;
}

.mia i {
  font-size: 6rem;
}

.mia {
  color: #808080;
}

.popover {
  z-index: 1049;
}

/* 2.8.5 | 2023-06-16 | mmcc | DFCT0011586 - User Profile should NOT overlap on the Profile component; added */
.user-profile-container-modal {
  border-radius: 0;
  bottom: 60px;
  margin: 0 auto;
  max-width: 650px;
  overflow: hidden;
  padding: 0 40px;
  position: absolute;
  top: 10px;
  width: 100%;;
}

/* 2.8.5 | 2023-06-16 | mmcc | DFCT0011586 - User Profile should NOT overlap on the Profile component; added */
.user-profile-container-standard {
  border-radius: 0;
  bottom: 60px;
  margin: 0 auto;
  max-width: 755px;
  overflow: hidden;
  padding: 0 20px;
  position: absolute;
  top: 10px;
  width: 100%;
}

.input-switch input[type=checkbox]:checked ~ .switch {
	background-color: $brand-primary;
}

// accessible accessibility toggle
@media screen and (-ms-high-contrast: active) {
  .input-switch input.ng-not-empty+label.switch[for="accessibility-enabled"] {
    background-color: highlight;
    border: none;

    &:before {
      background-color: highlightText;
    }
  }

  .input-switch input.ng-empty+label[for="accessibility-enabled"] {
    background-color: window;
    border: 1px solid windowText;

    &:before {
      background-color: windowText;
    }
  }
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// Cloned from Global User Profile
//
//
//------------------------------------------------------------------------------------------------------------------------
//
// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//                                      In HTML, added a footer div for Cancel button
//                                      In Server script, added code to build Messages for the widget; 
//                                        made changes to run in a Scoped App
//                                      In Client controller, Added cancel and submit functions for their buttons
//                                      Changes made in HTML, Server script and Client controller
// 2.8.1 | 2022-11-21 | mmcc | STRY0132316 - Tasker User Profile Page- Add Component Selector - User Settings Container Widget
//                                      In HTML, dropped connect, teamExists and preferences blocks; added sp-widget widget="data.userPreferencesWidget"
//                                      In CSS, updated .user-profile-container padding 20px 8px
//                                      In Server script, added sysUserID, bifold, isModal and isTopWidget
//                                      In Client controller, dropped imports for  $window, $location, $uibModal; dropped connect and preferences blocks
//                                      Changes made in HTML, CSS, Server script and Client controller.
// 2.8.1 | 2022-11-23 | RAJ  | STRY0132318 - Tasker User Profile- New Component- "Out of Office Schedule" - Profile Card View
//																			In HTML - added profile card
//                                      In Server added isProfileCard input
// 2.8.1 | 2022-12-27 | mmcc | DFCT0011489 - Scroll bar does NOT display on the User Profile page. (Tasker User Settings Container)
//                                      In HTML, add CSS selectors to flex and has a stable gutter
//                                      Changes made in HTML.
// 2.8.1 | 2023-01-03 | mmcc | DFCT0011552 - Back button w/Arrow icon on the Out of Office History list view padding is incorrect
//                                      In HTML, add a flex column and grow; remove a div with class row
//                                      In CSS, update 3 CSS selectors 
//                                      Changes made in HTML and CSS.
// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal
//                                      In HTML, add ngClass to set bottom of the position for Modal; 
//                                      comment out block for Cancel/Submit
//                                      In Server script, comment out get message for cancel 
//                                      In Client controller, comment out onCancel()
//                                      Changes made in HTML, Server script and Client controller.
// 2.8.1 | 2023-01-30 | raj | STRY0135276 - POC - Data Table - Response Comment Update - User Profile Directive - move user profile scripts from TaskWidgetData into UerInfoScitps 
//                                      In Server script, get user out of office indicator
//                                      Changes made in HTML, set user out of office indicator
// 2.8.5 | 2023-06-16 | mmcc | DFCT0011586 - Existing Task form >"Show me all the Out of Office Schedules...">Tasker User Settings Container 
//                                       modal>"User Profile" should NOT overlap on the Profile component
//                                      In HTML, updated <div ngif !data.isProfileCard to remove CSS class default-focus-outline and user-profile-container;
//                                       ngclass user-profile-container-standard when data.isModal==false else user-profile-container-modal
//                                      In CSS, removed .user-profile-container and added .user-profile-container-modal and .user-profile-container-standard
//                                      Changes made in HTML, CSS.
// 2.8.4 | 2023-11-06 | raj  | STRY0146507 - Certification Support- Placeholder
//                                           Server Script Only - noted not changing, GlideRecord  cloned from OOTB widget
//																					- noted not changing, .get call  cloned from OOTB widget
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {

	data.sysUserID = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter('sys_id') || gs.getUserID();
	data.bifold = (input || {}).bifold || (options || {}).bifold || false;
	data.isModal = (input || {}).isModal || (options || {}).isModal || false;
	data.isTopWidget = (input || {}).isTopWidget || (options || {}).isTopWidget || false;
	// RAJ - STRY0132318
	data.isProfileCard = (input || {}).isProfileCard || (options || {}).isProfileCard || false;

	convertToBool(['bifold', 'isModal', 'isTopWidget', 'isProfileCard']);

	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; build Messages for the widget
	_buildMessages();

	var sysUserGR = new GlideRecord("sys_user");
	data.userExists = sysUserGR.get(data.sysUserID) && sysUserGR.canRead();

	// STRY0132318
	data.defaultOU =  new OrganizationalScripts().GetDisplayValueUserDefaultOU(data.sysUserID);

	if (data.userExists) {
		data.table = sysUserGR.getRecordClassName();
		data.name = sysUserGR.getValue("name");
		var loggedInSysUserID = gs.getUser().getID();

		data.liveProfileID = "";
		data.dateTimeFormat = gs.getDateTimeFormat();

		//get live profile id for sending connect messages
		if (GlidePluginManager().isActive('com.glideapp.live_common')) {
			// STRY0146507 - Certification Support- Placeholder - noted not changing, GlideRecord  cloned from OOTB widget
			var liveProfileGR = new GlideRecord("live_profile");
			liveProfileGR.addQuery("document", data.sysUserID);
			liveProfileGR.query();
			if (liveProfileGR.next()) {
				data.liveProfileID = liveProfileGR.getValue("sys_id");
				data.liveProfileModel = $sp.getForm("live_profile", data.liveProfileID)._fields;
				// live_profile short_description is shown here as "Bio", so popup label/hint must reflect that
				if (data.liveProfileModel.short_description) {
					data.liveProfileModel.short_description.label = gs.getMessage("Bio");
					data.liveProfileModel.short_description.hint = gs.getMessage("Biography");
				}
			}
		}

		data.isLoggedInUsersProfile = loggedInSysUserID.equals(data.sysUserID);
		var sysUserForm = $sp.getForm(data.table, data.sysUserID);
		data.sysUserView = sysUserForm._view;
		data.sysUserModel = sysUserForm._fields;
		data.sysUserModelList = [];

		for (var i = 0; i < data.sysUserView.length; i++) {
			data.sysUserModelList.push(data.sysUserModel[data.sysUserView[i].name]);
		}

		if(!input) {
			data.userPreferencesWidget = $sp.getWidget('user-preferences', {glyph: 'user', color: 'primary'});
		}

		// STRY0135276 get user out of office
		data.isOoO = new Out_of_Office().isUserOutOfOffice(data.sysUserID);

	}

	// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
	// Use this function to get Messages that will be used in this widget
	function _buildMessages() {
		// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal; comment out cancel
		// data.cancelButtonText = gs.getMessage('cancel');
		// data.submitButtonText = gs.getMessage('Tasker - Button - Confirm');
		// data.submitButtonTitle = gs.getMessage('Tasker - Button - Confirm');
	}

	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

})($sp, input, data, options, gs);
